use crate::common::{AppError,I64String,PageParams,PageResult,next_id};use crate::modules::system::dto::job_request::JobSaveRequest;use crate::modules::system::entity::sys_job::SysJob;use crate::modules::system::entity::sys_job_run_log::SysJobRunLog;use rbatis::RBatis;use serde::Deserialize;use std::{sync::Arc,time::Instant};
fn db(d:Option<&Arc<RBatis>>)->Result<&RBatis,AppError>{d.map(AsRef::as_ref).ok_or_else(||AppError::system("Rbatis database is not configured"))}fn valid(r:&JobSaveRequest)->Result<(),AppError>{if r.job_name.trim().is_empty()||r.cron_expression.split_whitespace().count()<5||r.cron_expression.len()>64{return Err(AppError::bad_request("jobName or cronExpression is invalid"))}if !matches!(r.executor_type.trim().to_ascii_lowercase().as_str(),"shell"|"bat"|"powershell"|"ps1"|"python"){return Err(AppError::bad_request("executorType is not supported"))}if r.script_file.trim().is_empty(){return Err(AppError::bad_request("scriptFile is required"))}Ok(())}
pub async fn list(d:Option<&Arc<RBatis>>,p:PageParams)->Result<PageResult<SysJob>,AppError>{let d=db(d)?;let rows:Vec<SysJob>=d.exec_decode("select id,job_name,cron_expression,executor_type,script_file,script_args,status,remark,deleted from sys_job where deleted=0 order by created_at desc limit ? offset ?",vec![rbs::value!(p.page_size),rbs::value!(((p.page-1)*p.page_size)as i64)]).await.map_err(|e|AppError::system(e.to_string()))?;#[derive(Deserialize)]struct C{total:i64}let c:Vec<C>=d.exec_decode("select count(*) total from sys_job where deleted=0",vec![]).await.map_err(|e|AppError::system(e.to_string()))?;Ok(PageResult{list:rows,total:I64String(c.first().map(|v|v.total).unwrap_or(0)),page:p.page,page_size:p.page_size})}
pub async fn detail(d:Option<&Arc<RBatis>>,id:i64)->Result<SysJob,AppError>{let rows:Vec<SysJob>=db(d)?.exec_decode("select id,job_name,cron_expression,executor_type,script_file,script_args,status,remark,deleted from sys_job where id=? and deleted=0",vec![rbs::value!(id)]).await.map_err(|e|AppError::system(e.to_string()))?;rows.into_iter().next().ok_or_else(||AppError::not_found("资源不存在"))}
pub async fn create(d:Option<&Arc<RBatis>>,r:JobSaveRequest)->Result<I64String,AppError>{valid(&r)?;let id=next_id();db(d)?.exec("insert into sys_job(id,job_name,cron_expression,executor_type,script_file,script_args,status,remark,deleted)values(?,?,?,?,?,?,?,?,0)",vec![rbs::value!(id),rbs::value!(r.job_name),rbs::value!(r.cron_expression),rbs::value!(r.executor_type.trim().to_ascii_lowercase()),rbs::value!(r.script_file),rbs::value!(r.script_args),rbs::value!(r.status.unwrap_or(1)),rbs::value!(r.remark)]).await.map_err(|e|AppError::system(e.to_string()))?;Ok(I64String(id))}
pub async fn update(d:Option<&Arc<RBatis>>,id:i64,r:JobSaveRequest)->Result<(),AppError>{detail(d,id).await?;valid(&r)?;db(d)?.exec("update sys_job set job_name=?,cron_expression=?,executor_type=?,script_file=?,script_args=?,status=?,remark=? where id=?",vec![rbs::value!(r.job_name),rbs::value!(r.cron_expression),rbs::value!(r.executor_type.trim().to_ascii_lowercase()),rbs::value!(r.script_file),rbs::value!(r.script_args),rbs::value!(r.status.unwrap_or(1)),rbs::value!(r.remark),rbs::value!(id)]).await.map_err(|e|AppError::system(e.to_string()))?;Ok(())}
pub async fn delete(d:Option<&Arc<RBatis>>,id:i64)->Result<(),AppError>{detail(d,id).await?;db(d)?.exec("update sys_job set deleted=1 where id=?",vec![rbs::value!(id)]).await.map_err(|e|AppError::system(e.to_string()))?;Ok(())}pub async fn status(d:Option<&Arc<RBatis>>,id:i64,status:i32)->Result<(),AppError>{if !matches!(status,0|1){return Err(AppError::bad_request("status is invalid"))}detail(d,id).await?;db(d)?.exec("update sys_job set status=? where id=?",vec![rbs::value!(status),rbs::value!(id)]).await.map_err(|e|AppError::system(e.to_string()))?;Ok(())}
pub async fn run(d:Arc<RBatis>,id:i64)->Result<(),AppError>{let job=detail(Some(&d),id).await?;let log_id=next_id();d.exec("insert into sys_job_run_log(id,job_id,job_name,status,started_at,cost_ms)values(?,?,?,'RUNNING',now(),0)",vec![rbs::value!(log_id),rbs::value!(id),rbs::value!(&job.job_name)]).await.map_err(|e|AppError::system(e.to_string()))?;tokio::spawn(async move{let started=Instant::now();let result=execute(&job).await;let (status,error)=match result{Ok(_)=>("SUCCESS",None),Err(e)=>("FAIL",Some(e.message.chars().take(512).collect::<String>()))};let _=d.exec("update sys_job_run_log set status=?,finished_at=now(),cost_ms=?,error_message=? where id=?",vec![rbs::value!(status),rbs::value!(started.elapsed().as_millis()as i64),rbs::value!(error),rbs::value!(log_id)]).await;});Ok(())}
async fn execute(job:&SysJob)->Result<(),AppError>{let script=job.script_file.as_deref().ok_or_else(||AppError::bad_request("scriptFile is required"))?;let root=std::env::current_dir().map_err(|e|AppError::system(e.to_string()))?.join("..\\scripts").canonicalize().map_err(|_|AppError::system("scripts directory is not configured"))?;let path=root.join(script).canonicalize().map_err(|_|AppError::bad_request("script path is not allowed"))?;if !path.starts_with(&root){return Err(AppError::bad_request("script path is not allowed"))}let mut cmd=match job.executor_type.as_str(){"shell"=>{let mut c=tokio::process::Command::new("bash");c.arg(&path);c},"bat"=>{let mut c=tokio::process::Command::new("cmd.exe");c.args(["/c",path.to_string_lossy().as_ref()]);c},"powershell"|"ps1"=>{let mut c=tokio::process::Command::new("powershell.exe");c.args(["-ExecutionPolicy","Bypass","-File",path.to_string_lossy().as_ref()]);c},"python"=>{let mut c=tokio::process::Command::new("python");c.arg(&path);c},_=>return Err(AppError::bad_request("executorType is not supported"))};if let Some(args)=job.script_args.as_deref(){cmd.args(args.split_whitespace());}let result=tokio::time::timeout(std::time::Duration::from_secs(1800),cmd.status()).await.map_err(|_|AppError::system("script execution timed out"))?.map_err(|e|AppError::system(e.to_string()))?;if result.success(){Ok(())}else{Err(AppError::system(format!("script execution failed, exit code: {}",result.code().unwrap_or(-1))))}}
pub async fn run_logs(d:Option<&Arc<RBatis>>,p:PageParams,job_id:Option<i64>)->Result<PageResult<SysJobRunLog>,AppError>{let d=db(d)?;let where_sql=if job_id.is_some(){"where job_id=?"}else{""};let mut args=Vec::new();if let Some(id)=job_id{args.push(rbs::value!(id))}args.push(rbs::value!(p.page_size));args.push(rbs::value!(((p.page-1)*p.page_size)as i64));let rows:Vec<SysJobRunLog>=d.exec_decode(&format!("select id,job_id,job_name,status,started_at,finished_at,cost_ms,error_message from sys_job_run_log {where_sql} order by started_at desc limit ? offset ?"),args).await.map_err(|e|AppError::system(e.to_string()))?;Ok(PageResult{list:rows,total:I64String(0),page:p.page,page_size:p.page_size})}
